#!/usr/bin/env node
const r=require("readline").createInterface({input:process.stdin});const t=[{name:"visual_check",description:"Screenshot a URL and analyze for visual bugs using AI. Returns whether issues exist, a summary, and a detailed issues list.",inputSchema:{type:"object",properties:{url:{type:"string",description:"URL to visually check (must be publicly accessible)"}},required:["url"]}}];r.on("line",l=>{try{const q=JSON.parse(l);if(!q.id)return;let res;switch(q.method){case"ping":res={jsonrpc:"2.0",id:q.id,result:{}};break;case"initialize":res={jsonrpc:"2.0",id:q.id,result:{protocolVersion:"2024-11-05",capabilities:{tools:{}},serverInfo:{name:"perceptdot",version:"1.0.0"}}};break;case"tools/list":res={jsonrpc:"2.0",id:q.id,result:{tools:t}};break;default:res={jsonrpc:"2.0",id:q.id,error:{code:-32601,message:"Method not found: "+q.method}};}process.stdout.write(JSON.stringify(res)+"\n");}catch{}});
